var posTransitionPrior = function(pos) {
  // Dirichlet-drift priors for transitions from each POS
  var alpha = 1.5; // concentration parameter

  if (pos === 'start') {
    return Categorical({ps: [0.7, 0.3], vs: ['N', 'V']});
