    return Categorical({ps: [0.5, 0.4, 0.1], vs: ['V', 'N', 'stop']});
  } else if (pos === 'V') {
    // From verb, likely to go to noun or stop
    return Categorical({ps: [0.5, 0.3, 0.2], vs: ['N', 'V', 'stop']});
  }
};

var wordPrior = function(pos) {
  // Generate words given part of speech
